"use client";

import Image from "next/image";
import { Calendar1 } from "@/components/beste/piece/calendar1";
import { Terminal2 } from "@/components/beste/piece/terminal2";
import { Upload1 } from "@/components/beste/piece/upload1";
import { Badge } from "@/components/ui/badge";
import { cn } from "@/lib/utils";

type ComponentBackground =
  | { type: "dots" }
  | { type: "none" }
  | { type: "image"; src: string; alt?: string }
  | { type: "video"; src: string; alt?: string };

type StepMedia =
  | { type: "image"; src: string; alt?: string }
  | { type: "video"; src: string; alt?: string }
  | {
      type: "component";
      component: React.ReactNode;
      background?: ComponentBackground;
    };

interface StepCard {
  title: string;
  description: string;
  media: StepMedia;
}

interface Feature9Props {
  badge?: {
    label: string;
    variant?: "default" | "secondary" | "outline";
  };
  heading?: string;
  description?: string;
  cards?: StepCard[];
  className?: string;
}

export const feature9Demo: Feature9Props = {
  badge: { label: "How it works", variant: "outline" },
  heading: "Ship your next release in three steps",
  description:
    "Each step shows the surface you'll touch — a real asset, not a mockup — so the workflow stays grounded in what your team actually sees.",
  cards: [
    {
      title: "Drop in your assets",
      description:
        "Upload designs, brand guidelines, or reference images. The upload card tracks progress so the team knows when it's safe to start.",
      media: {
        type: "component",
        component: (
          <Upload1 filename="brand-guidelines.pdf" size="12.4 MB" progress={68} />
        ),
      },
    },
    {
      title: "Plan the release window",
      description:
        "A single calendar tile keeps the launch date front and center. Tone reflects whether you're on track or running hot.",
      media: {
        type: "component",
        background: { type: "none" },
        component: (
          <Calendar1 month="APR" day="21" weekday="Tuesday" tone="primary" />
        ),
      },
    },
    {
      title: "Ship the change",
      description:
        "One copy-and-paste command pushes the release. The terminal pill drops into changelogs and onboarding docs without extra wiring.",
      media: {
        type: "component",
        component: (
          <Terminal2 command="pnpm dlx shadcn@latest add feature9" />
        ),
      },
    },
  ],
};

export function Feature9({
  badge,
  heading,
  description,
  cards = [],
  className,
}: Feature9Props) {
  return (
    <section className={cn("py-16 md:py-24", className)}>
      <div className="mx-auto max-w-6xl px-4 md:px-6">
        <div className="mx-auto mb-9 max-w-2xl text-center">
          {badge && (
            <div className="mb-4 flex justify-center">
              <Badge variant={badge.variant ?? "default"}>{badge.label}</Badge>
            </div>
          )}
          {heading && (
            <h2 className="mb-4 text-2xl font-semibold tracking-tight md:text-4xl">
              {heading}
            </h2>
          )}
          {description && (
            <p className="text-base md:text-lg text-muted-foreground">
              {description}
            </p>
          )}
        </div>

        <div className="flex flex-col items-stretch justify-center gap-6 md:flex-row">
          {cards.map((card, index) => (
            <article
              key={index}
              className="flex w-full flex-col gap-3 rounded-md border bg-muted/30 p-6 md:w-[350px]"
            >
              <h3 className="text-base font-medium md:text-lg">{card.title}</h3>
              <p className="text-sm text-muted-foreground md:text-base">
                {card.description}
              </p>
              <div className="mt-auto pt-4">
                <StepMediaSurface media={card.media} />
              </div>
            </article>
          ))}
        </div>
      </div>
    </section>
  );
}

function StepMediaSurface({ media }: { media: StepMedia }) {
  const componentBackground =
    media.type === "component" ? media.background ?? { type: "dots" } : null;
  const showDots = componentBackground?.type === "dots";

  return (
    <div
      className="relative flex aspect-[4/3] items-center justify-center overflow-hidden rounded-md border bg-card"
      style={
        showDots
          ? {
              backgroundImage:
                "radial-gradient(circle, var(--border) 1px, transparent 1px)",
              backgroundSize: "16px 16px",
            }
          : undefined
      }
    >
      {componentBackground?.type === "image" && (
        <Image
          src={componentBackground.src}
          alt={componentBackground.alt ?? ""}
          fill
          className="object-cover"
          aria-hidden="true"
        />
      )}
      {componentBackground?.type === "video" && (
        <video
          src={componentBackground.src}
          autoPlay
          loop
          muted
          playsInline
          className="absolute inset-0 size-full object-cover"
        />
      )}

      {media.type === "video" ? (
        <video
          src={media.src}
          autoPlay
          loop
          muted
          playsInline
          aria-label={media.alt}
          className="size-full object-cover"
        />
      ) : media.type === "image" ? (
        <Image
          src={media.src}
          alt={media.alt ?? ""}
          fill
          className="object-cover"
        />
      ) : (
        <div className="relative flex size-full items-center justify-center">
          {media.component}
        </div>
      )}
    </div>
  );
}

"use client";

import { cn } from "@/lib/utils";

type Tone = "foreground" | "primary" | "destructive";

interface Calendar1Props {
  month?: string;
  day?: string;
  weekday?: string;
  tone?: Tone;
  className?: string;
}

const toneStripClasses: Record<Tone, string> = {
  foreground: "bg-foreground text-background",
  primary: "bg-primary text-primary-foreground",
  destructive: "bg-destructive text-white",
};

export const calendar1Demo: Calendar1Props = {
  month: "APR",
  day: "21",
  weekday: "Tuesday",
  tone: "destructive",
};

export function Calendar1({
  month,
  day,
  weekday,
  tone = "destructive",
  className,
}: Calendar1Props) {
  return (
    <div
      className={cn(
        "relative flex size-full items-center justify-center p-4",
        className
      )}
    >
      <div className="flex w-24 flex-col overflow-hidden rounded-lg border border-border bg-card shadow-sm">
        <div
          className={cn(
            "flex h-5 items-center justify-center text-xs font-bold uppercase tracking-wider",
            toneStripClasses[tone]
          )}
        >
          {month}
        </div>
        <div className="flex flex-col items-center gap-0.5 px-2 py-2">
          <span className="text-3xl font-bold leading-none tabular-nums text-card-foreground">
            {day}
          </span>
          <span className="text-xs font-medium uppercase tracking-wide text-muted-foreground">
            {weekday}
          </span>
        </div>
      </div>
    </div>
  );
}

"use client";

import { Check, Copy } from "lucide-react";
import { useState } from "react";
import { cn } from "@/lib/utils";

interface Terminal2Props {
  command?: string;
  className?: string;
}

export const terminal2Demo: Terminal2Props = {
  command: "pnpm dlx shadcn@latest add button",
};

export function Terminal2({ command = "", className }: Terminal2Props) {
  const [copied, setCopied] = useState(false);

  const handleCopy = async () => {
    try {
      await navigator.clipboard.writeText(command);
      setCopied(true);
      setTimeout(() => setCopied(false), 1400);
    } catch {
      /* noop */
    }
  };

  return (
    <div
      className={cn(
        "relative flex size-full items-center justify-center p-4",
        className
      )}
    >
      <div className="flex w-full max-w-72 items-center gap-2 rounded-lg border border-border bg-muted py-1.5 pl-3 pr-1.5 shadow-sm">
        <span
          className="shrink-0 select-none text-xs font-medium text-muted-foreground"
          aria-hidden="true"
        >
          ›
        </span>
        <code className="flex-1 truncate font-mono text-xs text-card-foreground">
          {command}
        </code>
        <button
          type="button"
          onClick={handleCopy}
          className="flex size-7 shrink-0 items-center justify-center rounded-md border border-transparent text-muted-foreground transition-colors hover:border-border hover:bg-card hover:text-card-foreground"
          aria-label={copied ? "Copied" : "Copy command"}
        >
          {copied ? (
            <Check className="size-3.5 text-emerald-500" />
          ) : (
            <Copy className="size-3.5" />
          )}
        </button>
      </div>
    </div>
  );
}

"use client";

import { FileText } from "lucide-react";
import { cn } from "@/lib/utils";

interface Upload1Props {
  filename?: string;
  size?: string;
  progress?: number;
  className?: string;
}

export const upload1Demo: Upload1Props = {
  filename: "brand-guidelines.pdf",
  size: "12.4 MB",
  progress: 68,
};

export function Upload1({
  filename,
  size,
  progress = 0,
  className,
}: Upload1Props) {
  const pct = Math.max(0, Math.min(100, progress));

  return (
    <div
      className={cn(
        "relative flex size-full items-center justify-center p-4",
        className
      )}
    >
      <div className="flex w-full max-w-60 flex-col gap-2 rounded-lg border border-border bg-card p-3 shadow-sm">
        <div className="flex items-center gap-2.5">
          <div className="flex size-9 shrink-0 items-center justify-center rounded-md bg-sky-500/10 text-sky-600 dark:text-sky-400">
            <FileText className="size-4" aria-hidden="true" />
          </div>
          <div className="flex min-w-0 flex-1 flex-col">
            <span className="truncate text-xs font-medium text-card-foreground">
              {filename}
            </span>
            <span className="text-xs text-muted-foreground">
              {size} · {pct}%
            </span>
          </div>
        </div>
        <div className="h-1 w-full overflow-hidden rounded-full bg-muted">
          <div
            className="h-full rounded-full bg-sky-500 transition-all"
            style={{ width: `${pct}%` }}
          />
        </div>
      </div>
    </div>
  );
}
